  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Looking for ways to speed up your queries, or scale easily with your serverless or edge functions?\n// Try Prisma Accelerate: https://pris.ly/cli/accelerate-init\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// 3. Define the data models for the LMS.\n\n// ENUMS for data consistency\nenum UserRole {\n  STUDENT\n  INSTRUCTOR\n  ADMIN\n}\n\nenum LessonType {\n  VIDEO\n  TEXT\n  QUIZ\n}\n\n// CORE MODELS\n\nmodel User {\n  id               String           @id @default(cuid())\n  email            String           @unique\n  name             String\n  password         String\n  role             UserRole         @default(STUDENT)\n  createdAt        DateTime         @default(now())\n  updatedAt        DateTime         @updatedAt\n  isVerified       Boolean          @default(false)\n  otp_secret       String?\n  otp_count        Int?             @default(0)\n  otp_generated_at DateTime?\n  taughtCourses    Course[]         @relation(\"InstructorCourses\")\n  enrollments      Enrollment[]\n  progress         UserProgress[]\n  quizSubmissions  QuizSubmission[]\n\n  @@index([email])\n}\n\nmodel Course {\n  id           String       @id @default(cuid())\n  title        String\n  slug         String       @unique\n  description  String?      @db.Text\n  imageUrl     String?\n  price        Float        @default(0.0)\n  isPublished  Boolean      @default(false)\n  createdAt    DateTime     @default(now())\n  updatedAt    DateTime     @updatedAt\n  instructorId String\n  instructor   User         @relation(\"InstructorCourses\", fields: [instructorId], references: [id], onDelete: Cascade)\n  categoryId   String\n  category     Category     @relation(fields: [categoryId], references: [id])\n  modules      Module[]\n  attachments  Attachment[]\n  enrollments  Enrollment[]\n\n  @@index([instructorId])\n  @@index([categoryId])\n  @@index([slug])\n}\n\nmodel Category {\n  id      String   @id @default(cuid())\n  name    String   @unique\n  courses Course[]\n}\n\nmodel Module {\n  id        String   @id @default(cuid())\n  title     String\n  order     Int\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  courseId  String\n  course    Course   @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  lessons   Lesson[]\n\n  @@unique([courseId, order])\n  @@index([courseId])\n}\n\nmodel Lesson {\n  id           String         @id @default(cuid())\n  title        String\n  type         LessonType\n  content      String?        @db.Text\n  videoUrl     String?\n  order        Int\n  moduleId     String\n  userProgress UserProgress[]\n  module       Module         @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  quiz         Quiz?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([moduleId, order])\n  @@index([moduleId])\n}\n\n// JOIN TABLES & SUPPORTING MODELS\n\nmodel Enrollment {\n  id         String   @id @default(cuid())\n  enrolledAt DateTime @default(now())\n  userId     String\n  courseId   String\n\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  course Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, courseId])\n  @@index([userId])\n  @@index([courseId])\n}\n\nmodel UserProgress {\n  id          String    @id @default(cuid())\n  isCompleted Boolean   @default(false)\n  completedAt DateTime?\n  userId      String\n  lessonId    String\n\n  // Relations\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  lesson Lesson @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n\n  // A user can only have one progress record per lesson\n  @@unique([userId, lessonId])\n  @@index([userId])\n  @@index([lessonId])\n}\n\nmodel Attachment {\n  id        String   @id @default(cuid())\n  name      String\n  url       String\n  createdAt DateTime @default(now())\n\n  // An attachment belongs to a course\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  @@index([courseId])\n}\n\n// QUIZ RELATED MODELS\n\nmodel Quiz {\n  id String @id @default(cuid())\n\n  // A quiz is directly linked to a lesson of type QUIZ\n  lessonId    String           @unique\n  lesson      Lesson           @relation(fields: [lessonId], references: [id], onDelete: Cascade)\n  questions   Question[]\n  submissions QuizSubmission[]\n}\n\nmodel Question {\n  id          String       @id @default(cuid())\n  text        String       @db.Text\n  quizId      String\n  quiz        Quiz         @relation(fields: [quizId], references: [id], onDelete: Cascade)\n  options     Option[]\n  userAnswers UserAnswer[]\n\n  @@index([quizId])\n}\n\nmodel Option {\n  id          String       @id @default(cuid())\n  text        String\n  isCorrect   Boolean      @default(false)\n  questionId  String\n  question    Question     @relation(fields: [questionId], references: [id], onDelete: Cascade)\n  userAnswers UserAnswer[]\n\n  @@index([questionId])\n}\n\nmodel QuizSubmission {\n  id          String       @id @default(cuid())\n  submittedAt DateTime     @default(now())\n  score       Float\n  userId      String\n  quizId      String\n  user        User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  quiz        Quiz         @relation(fields: [quizId], references: [id], onDelete: Cascade)\n  userAnswers UserAnswer[]\n\n  @@index([userId, quizId])\n}\n\nmodel UserAnswer {\n  id String @id @default(cuid())\n\n  // Links a user's submission, the question, and the chosen option\n  submissionId String\n  questionId   String\n  optionId     String\n\n  // Relations\n  submission QuizSubmission @relation(fields: [submissionId], references: [id], onDelete: Cascade)\n  question   Question       @relation(fields: [questionId], references: [id], onDelete: Cascade)\n  option     Option         @relation(fields: [optionId], references: [id], onDelete: Cascade)\n\n  @@unique([submissionId, questionId]) // User can only answer a question once per submission\n}\n",
